import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { studentsAPI, teachersAPI } from '../../services/api';
import Card from '../../components/common/Card';
import toast from 'react-hot-toast';
import { Users, Search, Eye } from 'lucide-react';

const AdvisoryStudents = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedStudent, setSelectedStudent] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const response = await teachersAPI.getById(user.id);
      if (response.data.success) {
        setProfile(response.data.teacher);

        // Fetch students in advisory section
        if (response.data.teacher.section_advisory) {
          const studentsRes = await studentsAPI.getBySection(response.data.teacher.section_advisory);
          if (studentsRes.data.success) {
            setStudents(studentsRes.data.students);
          }
        }
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredStudents = students.filter(s => 
    `${s.first_name} ${s.last_name} ${s.student_id}`.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  if (!profile?.section_advisory) {
    return (
      <div className="space-y-6 animate-fade-in">
        <h1 className="text-2xl font-bold text-secondary-800">Advisory Students</h1>
        <Card>
          <div className="text-center py-12">
            <Users className="w-16 h-16 mx-auto mb-4 text-secondary-300" />
            <h3 className="text-lg font-medium text-secondary-600 mb-2">No Advisory Section Assigned</h3>
            <p className="text-secondary-500">You are not currently assigned as an adviser to any section.</p>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-secondary-800">Advisory Students</h1>
          <p className="text-secondary-500">Section {profile.section_advisory}</p>
        </div>
        <div className="flex items-center gap-2 bg-blue-50 px-4 py-2 rounded-lg">
          <Users className="w-5 h-5 text-blue-600" />
          <span className="font-medium text-blue-700">{students.length} Students</span>
        </div>
      </div>

      {/* Search */}
      <div className="relative max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-secondary-400" />
        <input
          type="text"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          placeholder="Search students..."
          className="input-field pl-10"
        />
      </div>

      {/* Students Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredStudents.map((student) => (
          <Card key={student.id} className="hover:shadow-md transition-shadow">
            <div className="flex items-start gap-4">
              <div className="w-12 h-12 bg-primary-100 rounded-full flex items-center justify-center flex-shrink-0">
                {student.profile_picture ? (
                  <img
                    src={student.profile_picture}
                    alt={student.first_name}
                    className="w-full h-full rounded-full object-cover"
                  />
                ) : (
                  <span className="text-primary-600 font-medium">
                    {student.first_name[0]}{student.last_name[0]}
                  </span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-medium text-secondary-800 truncate">
                  {student.first_name} {student.last_name}
                </h3>
                <p className="text-sm text-secondary-500">{student.student_id}</p>
                <div className="flex items-center gap-2 mt-2">
                  <span className={`text-xs px-2 py-1 rounded ${
                    student.status_record === 'Regular'
                      ? 'bg-green-100 text-green-700'
                      : student.status_record === 'Irregular'
                      ? 'bg-yellow-100 text-yellow-700'
                      : 'bg-red-100 text-red-700'
                  }`}>
                    {student.status_record}
                  </span>
                </div>
              </div>
            </div>
          </Card>
        ))}
      </div>

      {filteredStudents.length === 0 && (
        <Card>
          <div className="text-center py-8 text-secondary-500">
            <Users className="w-12 h-12 mx-auto mb-3 text-secondary-300" />
            <p>No students found</p>
          </div>
        </Card>
      )}
    </div>
  );
};

export default AdvisoryStudents;
